const input = $input.item.json;
const raw = typeof input.data === 'string' ? JSON.parse(input.data) : input;

const leadOrganizado = {
  lead_id: raw.id,
  lead_name: raw.name,
  pipeline_id: raw.pipeline_id,
  status_id: raw.status_id,
  price: raw.price,
  responsible_user_id: raw.responsible_user_id,
  group_id: raw.group_id,
  created_by: raw.created_by,
  updated_by: raw.updated_by,
  created_at_unix: raw.created_at,
  updated_at_unix: raw.updated_at,
  closed_at: raw.closed_at,
  loss_reason_id: raw.loss_reason_id,
  account_id: raw.account_id,
  score: raw.score,
  is_deleted: raw.is_deleted,
  tags: raw._embedded?.tags || [],
  companies: raw._embedded?.companies || [],
  contacts: raw._embedded?.contacts || [],
  custom_fields_values_raw: raw.custom_fields_values || [],
  custom_fields: {}
};

if (raw.custom_fields_values && Array.isArray(raw.custom_fields_values)) {
  raw.custom_fields_values.forEach(field => {
    const key = field.field_code || field.field_name || field.field_id;
    const val = field.values[0] ? field.values[0].value : null;
    leadOrganizado.custom_fields[key] = val;
  });
}

return { json: leadOrganizado };

// =============================================
// NORMALIZAÇÃO
// =============================================
const normalize = s => s
  .toLowerCase()
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .replace(/\s+/g, '');

// =============================================
// MAPEAMENTO: pipeline venda → pipeline pós-venda
// =============================================
const pipelineMap = {
  9361827:  9439751,  // Hotel Termas → Pós-vendas Termas
  9377539:  9439759,  // Internacional → Pós-vendas Inter
  9377947:  9439771,  // Termas do Lago → Pós-vendas Lago
  9379711:  9439779,  // Cabanas Termas Hotel → Pós-vendas Cabanas
  9391183:  9439799,  // Fazzenda → Pós-vendas Fazzenda
  9392163:  9439803,  // Itá Thermas → Pós-vendas Itá
  9418391:  9439819,  // Mabu Thermas Foz → Pós-vendas Mabu
  9515771:  9515763,  // Recanto Cataratas → Pós-vendas Recanto Cataratas
  10211815: 10211923, // Costao do Santinho → Pós-vendas Costao
  10637211: 10661643, // Lagos de Jurema → Pós-vendas Lagos de Jurema
  10637219: 10661655, // Jardins de Jurema → Pós-vendas Jardins de Jurema
  10835031: 10835051, // Machadinho Thermas → Pós-vendas Machadinho
  11631008: 11633660, // Termas Park Hotel → Pós-vendas Termas Park
  12074732: 12074796, // Hotel Tirolesa → Pós-vendas Hotel Tirolesa
  12621844: 12622004, // Águas de Palmas → Pós-vendas Águas de Palmas
  12736543: 13010155, // Vivaz Cataratas → Pós-vendas Vivaz Cataratas
  13142691: 13142711, // Dona Francisca → Pós-vendas Dona Francisca
  12736635: 13232387, // Laghetto Resort Golden → Pós-vendas Laghetto Resort Golden
};

// =============================================
// PROCESSAR LEAD
// =============================================
const inputs = $input.all();
const lead = inputs[0].json;
const pipelinesData = inputs[1].json;

const customFields = lead.custom_fields || {};

// Mês da Reserva pelo field_id
const mesReservaRaw = (lead.custom_fields_values_raw || [])
  .find(f => f.field_id === 1033084)
  ?.values?.[0]?.value || '';
const mesReservaNorm = normalize(mesReservaRaw);

// Dados do lead
const pipelineId = lead.pipeline_id;
const posVendaPipelineId = pipelineMap[pipelineId];
const leadName = lead.lead_name || 'Lead';
const price = lead.price || 0;
const responsibleUserId = lead.responsible_user_id;
const contacts = lead.contacts || [];
const contactId = contacts[0]?.id || null;

// =============================================
// VALIDAÇÃO: pipeline mapeado?
// =============================================
if (!posVendaPipelineId) {
  return [{ json: {
    ok: false,
    erro: `Pipeline ${pipelineId} não mapeado para pós-venda`,
    pipeline_id: pipelineId,
    lead_id: lead.lead_id,
    lead_name: leadName
  }}];
}

// =============================================
// LER PIPELINE PÓS-VENDA DO CACHE
// =============================================
const pvPipeline = pipelinesData[String(posVendaPipelineId)];

if (!pvPipeline) {
  return [{ json: {
    ok: false,
    erro: `Pipeline pós-venda ${posVendaPipelineId} não encontrado no cache`,
    pipeline_id: pipelineId,
    lead_id: lead.lead_id,
    lead_name: leadName
  }}];
}

// =============================================
// MONTAR MAPA DE MESES E FALLBACK DINAMICAMENTE
// =============================================
const mesRegex = /^[a-záàãâéêíóôõúç]+ \d{4}$/i;
const fallbackRegex = /^vendas$/i;
const mesesMap = {};
let fallbackId = null;

for (const [statusId, statusName] of Object.entries(pvPipeline.statuses)) {
  const id = Number(statusId);
  const nome = statusName.trim();
  if (mesRegex.test(nome)) {
    mesesMap[normalize(nome)] = id;
  }
  if (!fallbackId && fallbackRegex.test(nome)) {
    fallbackId = id;
  }
}

if (!fallbackId) {
  return [{ json: {
    ok: false,
    erro: `Nenhum status de fallback (Venda Ganha/Realizada) encontrado no pipeline ${posVendaPipelineId}`,
    lead_id: lead.lead_id,
    lead_name: leadName
  }}];
}

// =============================================
// RESOLVER STATUS_ID
// =============================================
let statusId = fallbackId;
let statusResolucao = 'fallback';

if (mesReservaNorm) {
  const statusIdEncontrado = mesesMap[mesReservaNorm];
  if (statusIdEncontrado) {
    statusId = statusIdEncontrado;
    statusResolucao = 'mes_encontrado';
  } else {
    statusResolucao = 'mes_nao_encontrado_usando_fallback';
  }
} else {
  statusResolucao = 'mes_vazio_usando_fallback';
}

// =============================================
// MONTAR PAYLOAD DE CRIAÇÃO DO LEAD
// =============================================
const camposReplicar = [];
for (const cf of (lead.custom_fields_values_raw || [])) {
  const val = cf.values?.[0]?.value;
  if (val === null || val === undefined) continue;
  if (typeof val === 'object') continue;
  if (cf.field_id === 1055196) continue; // jul.ia_ativa — não replicar
  camposReplicar.push({ field_id: cf.field_id, values: [{ value: val }] });
}

const novoLead = {
  name: `Pós-venda: ${leadName}`,
  price: price,
  pipeline_id: posVendaPipelineId,
  status_id: statusId,
  responsible_user_id: responsibleUserId,
  custom_fields_values: camposReplicar,
  _embedded: {
    contacts: contactId ? [{ id: contactId }] : []
  }
};

return [{ json: {
  ok: true,
  lead_id_original: lead.lead_id,
  lead_name: leadName,
  pipeline_id_origem: pipelineId,
  pos_venda_pipeline_id: posVendaPipelineId,
  status_id: statusId,
  status_resolucao: statusResolucao,
  mes_reserva_raw: mesReservaRaw,
  mes_reserva_norm: mesReservaNorm,
  meses_disponiveis: Object.keys(mesesMap), // útil pra debug
  payload_novo_lead: novoLead
}}];

const input = $input.first().json;
const raw = typeof input.data === 'string' ? JSON.parse(input.data) : input;
const novoLeadId = raw._embedded?.leads?.[0]?.id;

if (!novoLeadId) {
  throw new Error('Falha ao criar lead pós-venda: ' + JSON.stringify(raw));
}

return [{ json: { novo_lead_id: novoLeadId, sucesso: true } }];

// Log do erro para auditoria — pipeline não mapeado
const d = $input.first().json;
console.log('PÓS-VENDA: pipeline não mapeado', JSON.stringify(d));
return [{ json: d }];

